/*
 * Minimal markdown renderer for dev-guideline preview.
 * Not a full CommonMark implementation — handles the subset used in
 * MEMORY.md, PROGRESS.md, and task files: headings, paragraphs, lists,
 * task-list checkboxes, bold/italic/inline code, fenced code blocks,
 * tables, blockquotes, links, and horizontal rules.
 */
(function () {
  function esc(s) {
    return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  }
  function inline(s) {
    s = esc(s);
    // inline code
    s = s.replace(/`([^`]+)`/g, function (_, c) { return "<code>" + c + "</code>"; });
    // bold
    s = s.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
    // italic
    s = s.replace(/(^|[\s(])\*([^*\s][^*]*?)\*/g, "$1<em>$2</em>");
    // links [text](url)
    s = s.replace(/\[([^\]]+)\]\(([^)\s]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');
    return s;
  }

  function render(md) {
    if (!md) return "";
    var lines = md.replace(/\r\n/g, "\n").split("\n");
    var out = [];
    var i = 0;

    function flushPara(buf) {
      if (buf.length) out.push("<p>" + inline(buf.join(" ")) + "</p>");
    }

    while (i < lines.length) {
      var line = lines[i];

      // fenced code
      if (/^```/.test(line)) {
        var lang = line.slice(3).trim();
        i++;
        var code = [];
        while (i < lines.length && !/^```/.test(lines[i])) {
          code.push(lines[i]); i++;
        }
        i++;
        out.push("<pre><code" + (lang ? ' class="lang-' + esc(lang) + '"' : "") + ">" + esc(code.join("\n")) + "</code></pre>");
        continue;
      }

      // heading
      var h = line.match(/^(#{1,6})\s+(.+)$/);
      if (h) {
        var lvl = h[1].length;
        out.push("<h" + lvl + ">" + inline(h[2]) + "</h" + lvl + ">");
        i++;
        continue;
      }

      // hr
      if (/^\s*([-*_])\s*\1\s*\1[\s\1]*$/.test(line)) {
        out.push("<hr>"); i++; continue;
      }

      // table
      if (/^\s*\|/.test(line) && i + 1 < lines.length && /^\s*\|?\s*:?-+/.test(lines[i + 1])) {
        var header = line.trim().replace(/^\|/, "").replace(/\|$/, "").split("|").map(function (c) { return c.trim(); });
        i += 2;
        var rows = [];
        while (i < lines.length && /^\s*\|/.test(lines[i])) {
          rows.push(lines[i].trim().replace(/^\|/, "").replace(/\|$/, "").split("|").map(function (c) { return c.trim(); }));
          i++;
        }
        var tbl = "<table><thead><tr>" + header.map(function (c) { return "<th>" + inline(c) + "</th>"; }).join("") + "</tr></thead><tbody>";
        rows.forEach(function (r) {
          tbl += "<tr>" + r.map(function (c) { return "<td>" + inline(c) + "</td>"; }).join("") + "</tr>";
        });
        tbl += "</tbody></table>";
        out.push(tbl);
        continue;
      }

      // blockquote
      if (/^>\s?/.test(line)) {
        var bq = [];
        while (i < lines.length && /^>\s?/.test(lines[i])) {
          bq.push(lines[i].replace(/^>\s?/, ""));
          i++;
        }
        out.push("<blockquote>" + render(bq.join("\n")) + "</blockquote>");
        continue;
      }

      // list (handles task-list checkboxes)
      if (/^\s*[-*+]\s+/.test(line)) {
        var items = [];
        while (i < lines.length && /^\s*[-*+]\s+/.test(lines[i])) {
          var item = lines[i].replace(/^\s*[-*+]\s+/, "");
          var task = item.match(/^\[([ xX])\]\s+(.*)$/);
          if (task) {
            var checked = task[1].toLowerCase() === "x";
            items.push('<li><input type="checkbox" disabled' + (checked ? " checked" : "") + "> " + inline(task[2]) + "</li>");
          } else {
            items.push("<li>" + inline(item) + "</li>");
          }
          i++;
        }
        out.push("<ul>" + items.join("") + "</ul>");
        continue;
      }

      // blank line → break paragraph
      if (/^\s*$/.test(line)) { i++; continue; }

      // paragraph (collect until blank/structural line)
      var p = [];
      while (i < lines.length && !/^\s*$/.test(lines[i])
             && !/^#{1,6}\s/.test(lines[i])
             && !/^```/.test(lines[i])
             && !/^\s*[-*+]\s+/.test(lines[i])
             && !/^>\s?/.test(lines[i])
             && !/^\s*\|/.test(lines[i])) {
        p.push(lines[i]); i++;
      }
      flushPara(p);
    }

    return out.join("\n");
  }

  window.marked = { parse: render };
})();
